import numpy as np

def random_crop(image: np.ndarray, crop_h: int, crop_w: int, seed: int = None) -> np.ndarray:
    rng = np.random.default_rng(seed)
    H, W = image.shape[:2]
    top = rng.integers(0, H - crop_h + 1)
    left = rng.integers(0, W - crop_w + 1)
    return image[top:top+crop_h, left:left+crop_w].copy()

def random_hflip(image: np.ndarray, p: float = 0.5, seed: int = None) -> np.ndarray:
    rng = np.random.default_rng(seed)
    if rng.random() < p:
        return np.flip(image, axis=1).copy()
    return image.copy()
